const b = $('Webhook · Sheet Headers').first().json.body;
const gsheetUrl = b.gsheet_url || '';
const match = gsheetUrl.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
if (!match) throw new Error('Invalid Google Sheet URL');
// Default to the first tab (gid=0) when the URL doesn't name one — far more
// forgiving than requiring an exact sheet-tab name match.
const gidMatch = gsheetUrl.match(/gid=(\d+)/);
const gid = gidMatch ? gidMatch[1] : '0';
return [{ json: { spreadsheetId: match[1], gid } }];

const raw = $input.first().json;
const csvText = typeof raw === 'string' ? raw : (raw.data ?? raw.body ?? raw.text ?? '');

// A sheet that isn't publicly viewable returns Google's HTML login/error page
// instead of CSV — surface that clearly instead of returning garbage headers.
if (!csvText || /^\s*<(!doctype|html)/i.test(csvText.trim())) {
  return [{ json: { headers: [], error: 'Could not read the sheet. In Google Sheets, use Share → General access → "Anyone with the link" (Viewer), then try again.' } }];
}

function parseCSVLine(text) {
  const row = [];
  let field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"') { if (text[i + 1] === '"') { field += '"'; i++; } else { inQuotes = false; } }
      else field += c;
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ',') { row.push(field); field = ''; }
      else if (c === '\r') { /* skip */ }
      else if (c === '\n') { break; } // stop at end of first line
      else field += c;
    }
  }
  row.push(field);
  return row;
}

const headers = parseCSVLine(csvText).map(h => String(h).trim()).filter(Boolean);
return [{ json: { headers } }];
